function todayStr(){const t=new Date();return `${t.getFullYear()}-${String(t.getMonth()+1).padStart(2,"0")}-${String(t.getDate()).padStart(2,"0")}`;}

// Freie Zeiten: Öffnungszeiten (So zu, Sa bis 14), Behandlungsdauer & belegte Slots der Fachkraft
function availTimes(y,m,day,dur,specialist,bookings){
  if(day==null)return[];
  const dow=new Date(y,m,day).getDay();
  if(dow===0)return[];
  const close=dow===6?14*60:19*60;
  const dateStr=`${y}-${String(m+1).padStart(2,"0")}-${String(day).padStart(2,"0")}`;
  const busy=bookings
    .filter(b=>b.status==="confirmed"&&b.date===dateStr&&b.specialist===specialist)
    .map(b=>{const[h,mm]=b.time.split(":").map(Number);const s=h*60+mm;return[s,s+(b.dur||60)];});
  return TIMES.filter(t=>{
    const[h,mm]=t.split(":").map(Number);const s=h*60+mm;const e=s+dur;
    if(e>close)return false;
    return !busy.some(([bs,be])=>s<be&&e>bs);
  });
}

function getDays(y,m){
  const first=new Date(y,m,1).getDay();
  const total=new Date(y,m+1,0).getDate();
  const pad=first===0?6:first-1;
  return [...Array(pad).fill(null),...Array.from({length:total},(_,i)=>i+1)];
}

// ── MINI CALENDAR ──
function MiniCal({year,month,setYear,setMonth,selDay,setSelDay,disablePast=true}){
  const days=getDays(year,month);
  const today=new Date();
  return(
    <div>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:16}}>
        <button onClick={()=>{if(month>0)setMonth(month-1);else{setMonth(11);setYear(year-1);}}} style={btn36}><ChevronLeft size={16} color="#6B2F5E"/></button>
        <span style={{fontWeight:700,fontSize:15,color:"#1C1B1F"}}>{MONTHS[month]} {year}</span>
        <button onClick={()=>{if(month<11)setMonth(month+1);else{setMonth(0);setYear(year+1);}}} style={btn36}><ChevronRight size={16} color="#6B2F5E"/></button>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",marginBottom:6}}>
        {DAYS_SHORT.map(d=><div key={d} style={{textAlign:"center",fontSize:11,fontWeight:700,color:"#A89BB0",padding:"2px 0"}}>{d}</div>)}
      </div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:2}}>
        {days.map((d,i)=>{
          if(!d) return <div key={i}/>;
          const isSel=selDay===d;
          const isToday=d===today.getDate()&&month===today.getMonth()&&year===today.getFullYear();
          const isSunday=new Date(year,month,d).getDay()===0;
          const isPast=(disablePast&&new Date(year,month,d)<new Date(today.getFullYear(),today.getMonth(),today.getDate()))||isSunday;
          return(
            <div key={i} style={{display:"flex",justifyContent:"center"}}>
              <button onClick={()=>!isPast&&setSelDay(d)} style={{
                width:36,height:36,borderRadius:"50%",border:isToday&&!isSel?"2px solid #8B4F7A":"none",
                background:isSel?"linear-gradient(135deg,#8B4F7A,#C084A8)":"transparent",
                color:isPast?"#D0C4D4":isSel?"#fff":"#1C1B1F",
                fontWeight:isSel?700:isToday?700:400,fontSize:13,cursor:isPast?"default":"pointer",
                fontFamily:"inherit",transition:"all 0.15s",
              }}>{d}</button>
            </div>
          );
        })}
      </div>
    </div>
  );
}

const btn36={background:"#F3EDF7",border:"none",borderRadius:12,width:36,height:36,display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer"};

// ── MODAL OVERLAY ──
function Modal({open,onClose,title,children}){
  if(!open)return null;
  return(
    <div style={{position:"fixed",inset:0,zIndex:300,display:"flex",flexDirection:"column",justifyContent:"flex-end",maxWidth:430,margin:"0 auto"}}>
      <div onClick={onClose} style={{flex:1,background:"rgba(0,0,0,0.4)",backdropFilter:"blur(4px)"}}/>
      <div style={{background:"#FFFBFF",borderRadius:"28px 28px 0 0",padding:"24px 20px 40px",maxHeight:"85vh",overflowY:"auto",animation:"slideUp 0.3s ease"}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}>
          <span style={{fontFamily:"Cormorant Garamond,serif",fontSize:22,fontWeight:600,color:"#2D1A27"}}>{title}</span>
          <button onClick={onClose} style={{background:"#F3EDF7",border:"none",borderRadius:12,width:36,height:36,display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer"}}><X size={18} color="#6B2F5E"/></button>
        </div>
        {children}
      </div>
    </div>
  );
}

